+    #[test]
+    fn test_constant_time_eq_basic() {
+        assert!(constant_time_eq("hello", "hello"));
+        assert!(!constant_time_eq("hello", "world"));
+        assert!(!constant_time_eq("hello", "hell"));
+        assert!(!constant_time_eq("", "a"));
+        assert!(constant_time_eq("", ""));
